def classify_query_type(query: str) -> float:
    """Return alpha based on heuristics."""
    tokens = query.split()
    # Short all-caps / alphanumeric → likely identifier query
    if len(tokens) <= 3 and any(t.isupper() or t[0].isdigit() for t in tokens):
        return 0.2          # lean BM25

    # Long natural-language question
    if len(tokens) > 12 and query.endswith("?"):
        return 0.8          # lean dense

    # Contains code patterns
    if any(c in query for c in [".", "()", "_", "::"]):
        return 0.35         # mild BM25 lean

    return 0.5              # default balanced

def adaptive_hybrid_search(query, retriever, k=10):
    alpha = classify_query_type(query)
    return retriever.search(query, alpha=alpha, k=k)
